/** Combat coverage log (seed 1): sign a contract, jump into the seeded
 *  encounter, then take every stance — fight (lands a hit, hull 2 -> 1), run
 *  (pilot check fails), talk (check fails) — carry the unresolved encounter
 *  across end-day, and finish it on day 2 with a fight that resolves
 *  `defeated` and completes the pending travel to system 2. */
export const REPLAY_LOG_COMBAT: ProtocolRequest[] = [
  { type: 'new-game', seed: 1 },
  { type: 'start-day' },
  {
    type: 'apply-action',
    action: { type: 'Trade', action: 'sign-contract', contractIndex: 0, spendDie: 0 },
  },
  { type: 'apply-action', action: { type: 'Travel', destinationId: 2, spendDie: 1 } },
  {
    type: 'apply-action',
    action: { type: 'Combat', stance: 'fight', targetId: 'npc-the-chef', spendDie: 2 },
  },
  {
    // T-1207: run is now an OPPOSED PILOT roll. Under seed 1 the die-3 slot
    // (value 7) TIES the enemy pursuit total and would ESCAPE (ties break to the
    // player), collapsing the encounter before the day boundary; the die-4 slot
    // (value 4) loses the opposed roll, so the run fails and the encounter
    // persists into day 2 as the fixture intends. Run + talk dice swapped to keep
    // the scenario intact.
    type: 'apply-action',
    action: { type: 'Combat', stance: 'run', targetId: 'npc-the-chef', spendDie: 4 },
  },
  {
    type: 'apply-action',
    action: { type: 'Combat', stance: 'talk', targetId: 'npc-the-chef', spendDie: 3 },
  },
  { type: 'end-day' },
  { type: 'start-day' },
  {
    type: 'apply-action',
    action: { type: 'Combat', stance: 'fight', targetId: 'npc-the-chef', spendDie: 0 },
  },
  { type: 'apply-action', action: { type: 'Wait' } },
  { type: 'end-day' },
];

